"use server";

import { db } from "@/lib/db";
import { apiKeys } from "@/lib/schema/api";
import { createSafeAction } from "@/lib/action-helpers";
import { z } from "zod";
import { eq, desc } from "drizzle-orm";
import { getSession } from "@/lib/session";
import { randomBytes } from "crypto";
import { revalidatePath } from "next/cache";
import { logAction } from "@/lib/audit";

const CreateApiKeySchema = z.object({
  name: z.string().min(1, "Название обязательно"),
});

const RevokeApiKeySchema = z.object({
  id: z.string().uuid(),
});

/**
 * Action to list all API keys for the current user.
 */
export async function getApiKeysAction() {
  const session = await getSession();
  if (!session) return { success: false, error: "Unauthorized" };

  try {
    const keys = await db.query.apiKeys.findMany({
      where: eq(apiKeys.userId, session.id),
      orderBy: [desc(apiKeys.createdAt)],
    });
    return { success: true, data: keys };
  } catch (error) {
    return { success: false, error: "Database error" };
  }
}

/**
 * Action to generate a new API key.
 */
export const createApiKey = createSafeAction(CreateApiKeySchema, async ({ name }) => {
  const session = await getSession();
  if (!session) return { success: false, error: "Unauthorized" };

  // Generate a random secure key: "mc_" prefix + 48 chars hex
  const keyContent = `mc_${randomBytes(24).toString("hex")}`;

  try {
    const [newKey] = await db.insert(apiKeys).values({
      name,
      key: keyContent,
      userId: session.id,
    }).returning();

    await logAction(
        `Создан API-ключ: ${name}`, 
        "api_key", 
        newKey.id, 
        { name, keyPrefix: keyContent.substring(0, 6) }
    );

    revalidatePath("/admin-panel/api-keys");
    return { success: true, data: newKey };
  } catch (error) {
    return { success: false, error: "Failed to create API key" };
  }
});

/**
 * Action to revoke an API key.
 */
export const revokeApiKey = createSafeAction(RevokeApiKeySchema, async ({ id }) => {
  const session = await getSession();
  if (!session) return { success: false, error: "Unauthorized" };

  try {
    const key = await db.query.apiKeys.findFirst({ where: eq(apiKeys.id, id) });
    if (!key) return { success: false, error: "Key not found" };

    await db.delete(apiKeys).where(eq(apiKeys.id, id));

    await logAction(
        `Отозван API-ключ: ${key.name}`, 
        "api_key", 
        id, 
        { name: key.name }
    );

    revalidatePath("/admin-panel/api-keys");
    return { success: true };
  } catch (error) {
    return { success: false, error: "Failed to revoke API key" };
  }
});

"use client";

import { useEffect, useState } from "react";
import { getApiKeysAction, createApiKey, revokeApiKey } from "./actions";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Loader2, Key, Trash2, Copy, Check, Plus } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";
import { ru } from "date-fns/locale";

interface ApiKeyData {
  id: string;
  name: string;
  key: string;
  createdAt: string;
  lastUsedAt?: string | null;
}

export default function ApiKeysPage() {
  const [keys, setKeys] = useState<ApiKeyData[]>([]);
  const [loading, setLoading] = useState(true);
  const [creating, setCreating] = useState(false);
  const [newKeyName, setNewKeyName] = useState("");
  const [copiedId, setCopiedId] = useState<string | null>(null);

  useEffect(() => {
    loadKeys();
  }, []);

  async function loadKeys() {
    setLoading(true);
    const result = await getApiKeysAction();
    if (result.success && result.data) {
      setKeys(result.data as any);
    }
    setLoading(false);
  }

  async function handleCreate() {
    if (!newKeyName.trim()) return;
    setCreating(true);
    const result = await createApiKey({ name: newKeyName });
    if (result.success) {
      toast.success("API ключ создан");
      setNewKeyName("");
      loadKeys();
    } else {
      toast.error("Не удалось создать ключ");
    }
    setCreating(false);
  }

  async function handleRevoke(id: string) {
    if (!confirm("Вы уверены, что хотите отозвать этот ключ? Это действие необратимо.")) return;
    const result = await revokeApiKey({ id });
    if (result.success) {
      toast.success("Ключ отозван");
      loadKeys();
    } else {
      toast.error("Не удалось отозвать ключ");
    }
  }

  function copyToClipboard(text: string, id: string) {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
    toast.success("Скопировано в буфер обмена");
  }

  if (loading && keys.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-24 space-$1-3">
        <Loader2 className="w-10 h-10 animate-spin text-primary opacity-50" />
        <p className="text-sm text-slate-500 font-bold">Загружаем ключи доступа...</p>
      </div>
    );
  }

  return (
    <div className="space-$1-3 pb-20">
      <div className="flex items-center gap-3">
        <div className="w-14 h-14 bg-primary/10 rounded-[22px] flex items-center justify-center border border-primary/20 shadow-sm shadow-primary/10">
          <Key className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="text-2xl font-black text-slate-900 tracking-tight">API Ключи доступа</h1>
          <p className="text-slate-500 text-xs font-bold tracking-wider mt-1">Публичный API v1.0 • Безопасная интеграция</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-3">
        <div className="lg:col-span-1">
          <Card className="border-2 border-slate-100 shadow-sm rounded-3xl overflow-hidden">
            <CardHeader className="bg-slate-50/50">
              <CardTitle className="text-lg font-black tracking-tight">Выпустить новый ключ</CardTitle>
              <CardDescription className="text-xs font-medium">Создайте уникальный ключ для внешней интеграции.</CardDescription>
            </CardHeader>
            <CardContent className="pt-6 space-$1-3">
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-500 px-1">Название ключа</label>
                <Input 
                  placeholder="Напр., Website Integration" 
                  value={newKeyName}
                  onChange={(e) => setNewKeyName(e.target.value)}
                  className="rounded-2xl border-2 focus-visible:ring-primary/20 h-12 font-bold"
                />
              </div>
              <Button 
                onClick={handleCreate} 
                disabled={creating || !newKeyName.trim()}
                className="w-full rounded-2xl h-12 font-black tracking-wide shadow-lg shadow-primary/20"
              >
                {creating ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Plus className="w-4 h-4 mr-2" />}
                Выпустить ключ
              </Button>
              <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 space-y-2">
                <p className="text-[10px] text-amber-800 font-bold leading-relaxed">
                  ВАЖНО: Ключ будет показан только один раз при создании. Сохраните его в безопасном месте.
                </p>
              </div>
            </CardContent>
          </Card>
        </div>

        <div className="lg:col-span-2">
          <Card className="border-2 border-slate-100 shadow-xl shadow-slate-200/50 rounded-[32px] overflow-hidden">
            <CardHeader className="border-b border-slate-100">
              <CardTitle className="flex items-center justify-between">
                <span className="font-black text-lg tracking-tight">Активные ключи</span>
                <Badge variant="secondary" className="rounded-lg h-6 font-bold">{keys.length}</Badge>
              </CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <div className="divide-y divide-slate-50">
                {keys.map((key) => (
                  <div key={key.id} className="p-6 flex items-center justify-between hover:bg-slate-50/50 transition-colors group">
                    <div className="space-y-1.5 flex-1 pr-8">
                      <div className="flex items-center gap-3">
                        <h3 className="font-black text-slate-800 tracking-tight">{key.name}</h3>
                        <Badge variant="success" className="h-5 text-[9px] px-1.5 rounded-md font-black">Active</Badge>
                      </div>
                      <code className="text-xs text-slate-400 font-mono bg-slate-100/50 px-2.5 py-1 rounded-lg border border-slate-100 inline-block">
                        {key.key.substring(0, 10)}**************************
                      </code>
                      <div className="flex items-center gap-3 pt-1">
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1.5">
                           Создан: {format(new Date(key.createdAt), "dd MMM yyyy", { locale: ru })}
                        </span>
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1.5">
                           Использован: {key.lastUsedAt ? format(new Date(key.lastUsedAt), "dd.MM HH:mm") : "Никогда"}
                        </span>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                      <Button 
                        variant="outline" 
                        size="icon" 
                        className="rounded-xl border-2 hover:bg-white hover:text-primary transition-all shadow-sm"
                        onClick={() => copyToClipboard(key.key, key.id)}
                      >
                        {copiedId === key.id ? <Check className="w-4 h-4 text-emerald-500" /> : <Copy className="w-4 h-4" />}
                      </Button>
                      <Button 
                        variant="outline" 
                        size="icon" 
                        className="rounded-xl border-2 hover:bg-rose-50 hover:text-rose-600 hover:border-rose-200 transition-all shadow-sm"
                        onClick={() => handleRevoke(key.id)}
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </div>
                ))}

                {keys.length === 0 && (
                  <div className="p-12 text-center space-$1-3">
                    <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto opacity-50">
                      <Key className="w-8 h-8 text-slate-400" />
                    </div>
                    <p className="text-slate-400 font-black text-sm">Ключи доступа не созданы</p>
                  </div>
                )}
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useTransition, useState, useEffect } from "react";
import { useRouter, usePathname, useSearchParams } from "next/navigation";
import { format } from "date-fns";
import { ru } from "date-fns/locale";
import { 
    Search, Filter, Calendar, User, ChevronLeft, ChevronRight, 
    Download, Eye, RefreshCw, X, Box, ShoppingCart, Users, Settings, Database, MoreHorizontal
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { ResponsiveModal } from "@/components/ui/responsive-modal";

interface AuditLog {
    id: string;
    userId: string | null;
    action: string;
    actionCategory: string | null;
    entityType: string;
    entityId: string;
    details: any;
    createdAt: string;
    user?: { name: string; email: string; avatar?: string | null };
}

interface AuditClientProps {
    initialLogs: AuditLog[];
    pagination: { total: number; page: number; limit: number; totalPages: number };
    users: { id: string; name: string }[];
}

const ENTITY_ICONS: Record<string, any> = {
    order: ShoppingCart,
    client: Users,
    warehouse: Box,
    system: Settings,
    role: Database,
    user: User,
    default: ActivityIcon
};

function ActivityIcon({ className }: { className?: string }) {
    return <RefreshCw className={className} />;
}

export function AuditClient({ initialLogs, pagination, users }: AuditClientProps) {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const [isPending, startTransition] = useTransition();

    const [selectedLog, setSelectedLog] = useState<AuditLog | null>(null);
    const [isDetailsOpen, setIsDetailsOpen] = useState(false);

    // Filter states
    const [search, setSearch] = useState(searchParams.get("search") || "");
    const [userId, setUserId] = useState(searchParams.get("userId") || "all");
    const [entityType, setEntityType] = useState(searchParams.get("entityType") || "all");
    const [startDate, setStartDate] = useState(searchParams.get("startDate") || "");
    const [endDate, setEndDate] = useState(searchParams.get("endDate") || "");

    const updateFilters = (params: Record<string, string | number | null>) => {
        const newParams = new URLSearchParams(searchParams.toString());
        Object.entries(params).forEach(([key, value]) => {
            if (value === null || value === "all" || value === "") {
                newParams.delete(key);
            } else {
                newParams.set(key, String(value));
            }
        });
        // Always reset to page 1 on filter change
        if (!params.page) newParams.delete("page");

        startTransition(() => {
            router.push(`${pathname}?${newParams.toString()}`);
        });
    };

    const handleSearchChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSearch(e.target.value);
    };

    const handleSearchSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        updateFilters({ search });
    };

    const handlePageChange = (newPage: number) => {
        updateFilters({ page: newPage });
    };

    const exportToCsv = () => {
        const headers = ["Дата", "Пользователь", "Действие", "Тип", "ID Сущности", "Детали"];
        const rows = initialLogs.map(log => [
            format(new Date(log.createdAt), "yyyy-MM-dd HH:mm:ss"),
            log.user?.name || "Система",
            log.action,
            log.entityType,
            log.entityId,
            JSON.stringify(log.details)
        ]);

        const csvContent = "data:text/csv;charset=utf-8," 
            + [headers, ...rows].map(e => e.join(",")).join("\n");

        const encodedUri = encodeURI(csvContent);
        const link = document.createElement("a");
        link.setAttribute("href", encodedUri);
        link.setAttribute("download", `audit_log_${format(new Date(), "yyyy-MM-dd")}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const getEntityIcon = (type: string) => {
        const Icon = ENTITY_ICONS[type] || ENTITY_ICONS.default;
        return <Icon className="w-full h-full" />;
    };

    const renderDiff = (details: any) => {
        if (!details) return <p className="text-slate-400 italic">Нет деталей</p>;

        // Check if it's a diff object
        const isDiff = Object.values(details).some((v: any) => v && typeof v === 'object' && ('old' in v || 'new' in v));

        if (!isDiff) {
            return (
                <div className="bg-slate-900 rounded-xl p-4 overflow-auto max-h-[400px]">
                    <pre className="text-xs text-blue-300">
                        {JSON.stringify(details, null, 2)}
                    </pre>
                </div>
            );
        }

        return (
            <div className="space-y-3">
                {Object.entries(details).map(([key, value]: [string, any]) => {
                    if (key === 'originalEntityId') return null;
                    return (
                        <div key={key} className="bg-white border border-slate-100 rounded-2xl p-4 shadow-sm">
                            <h4 className="text-xs font-black text-slate-400 mb-2">{key}</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                <div className="space-y-1">
                                    <span className="text-[10px] font-bold text-rose-500 px-2 py-0.5 bg-rose-50 rounded-lg">Было</span>
                                    <div className="p-3 bg-rose-50/30 rounded-xl border border-rose-100 text-sm font-medium text-slate-700 min-h-[40px]">
                                        {String(value.old ?? "—")}
                                    </div>
                                </div>
                                <div className="space-y-1">
                                    <span className="text-[10px] font-bold text-emerald-500 px-2 py-0.5 bg-emerald-50 rounded-lg">Стало</span>
                                    <div className="p-3 bg-emerald-50/30 rounded-xl border border-emerald-100 text-sm font-medium text-slate-800 min-h-[40px]">
                                        {String(value.new ?? "—")}
                                    </div>
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        );
    };

    return (
        <div className="space-$1-3">
            {/* Filters Bento Block */}
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-3">
                <div className="lg:col-span-2 crm-card p-4">
                    <form onSubmit={handleSearchSubmit} className="relative group">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-focus-within:text-primary transition-colors" />
                        <Input 
                            value={search}
                            onChange={handleSearchChange}
                            placeholder="Поиск по действию..." 
                            className="pl-10 h-11 bg-slate-50 border-slate-200 rounded-2xl font-medium focus:ring-primary/10 transition-all"
                        />
                    </form>
                </div>

                <div className="lg:col-span-1 crm-card p-4 flex gap-2">
                    <Select 
                        value={userId}
                        options={[
                            { id: "all", title: "Все пользователи" },
                            ...users.map(u => ({ id: u.id, title: u.name }))
                        ]}
                        className="h-11 flex-1"
                        onChange={(val) => updateFilters({ userId: val })}
                    />
                </div>

                <div className="lg:col-span-1 crm-card p-4 flex gap-2">
                    <Button 
                        onClick={exportToCsv}
                        variant="outline"
                        className="h-11 w-full rounded-2xl border-slate-200 hover:bg-slate-50 font-bold transition-all group"
                    >
                        <Download className="w-4 h-4 mr-2 group-hover:scale-110 transition-transform" />
                        SVG/Excel
                    </Button>
                </div>
            </div>

            {/* Entity Filter Chips */}
            <div className="flex flex-wrap gap-2 px-1">
                {["all", "order", "client", "warehouse", "role", "system"].map(type => (
                    <button
                        key={type}
                        onClick={() => updateFilters({ entityType: type })}
                        className={cn(
                            "px-4 py-2 rounded-2xl text-xs font-black transition-all border shadow-sm",
                            entityType === type 
                                ? "bg-primary text-white border-primary shadow-primary/20 scale-105" 
                                : "bg-white text-slate-500 border-slate-200 hover:border-primary/40 hover:text-primary"
                        )}
                    >
                        {type === 'all' ? 'Все' : type === 'order' ? 'Заказы' : type === 'client' ? 'Клиенты' : type === 'warehouse' ? 'Склад' : type === 'role' ? 'Роли' : 'Система'}
                    </button>
                ))}
            </div>

            {/* Main Table Block */}
            <div className="crm-card overflow-hidden">
                <div className="overflow-x-auto min-h-[400px]">
                    <table className="crm-table">
                        <thead className="crm-thead">
                            <tr>
                                <th className="crm-th w-[180px]">Дата и время</th>
                                <th className="crm-th">Действие</th>
                                <th className="crm-th">Кто</th>
                                <th className="crm-th">Сущность</th>
                                <th className="crm-th text-right">Детали</th>
                            </tr>
                        </thead>
                        <tbody className="crm-tbody">
                            {initialLogs.map((log) => (
                                <tr key={log.id} className="crm-tr group">
                                    <td className="crm-td">
                                        <div className="flex flex-col">
                                            <span className="text-sm font-bold text-slate-900">
                                                {format(new Date(log.createdAt), "d MMMM", { locale: ru })}
                                            </span>
                                            <span className="text-[10px] font-medium text-slate-400">
                                                {format(new Date(log.createdAt), "HH:mm:ss")}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="crm-td">
                                        <div className="flex items-center gap-3">
                                            <div className={cn(
                                                "w-8 h-8 rounded-xl flex items-center justify-center border",
                                                log.actionCategory === 'system' ? "bg-amber-50 border-amber-100 text-amber-500" : "bg-primary/5 border-primary/10 text-primary"
                                            )}>
                                                {getEntityIcon(log.entityType)}
                                            </div>
                                            <span className="text-sm font-bold text-slate-800">{log.action}</span>
                                        </div>
                                    </td>
                                    <td className="crm-td">
                                        <div className="flex items-center gap-2">
                                            <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-500 overflow-hidden relative">
                                                {log.user?.avatar ? (
                                                    <img src={log.user.avatar} className="object-cover w-full h-full" alt="" />
                                                ) : (
                                                    log.user?.name?.charAt(0) || "S"
                                                )}
                                            </div>
                                            <span className="text-xs font-bold text-slate-600 truncate max-w-[120px]">
                                                {log.user?.name || "Система"}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="crm-td">
                                        <Badge variant="outline" className="bg-slate-50 text-slate-500 font-bold border-none capitalize">
                                            {log.entityType}
                                        </Badge>
                                    </td>
                                    <td className="crm-td text-right">
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            onClick={() => {
                                                setSelectedLog(log);
                                                setIsDetailsOpen(true);
                                            }}
                                            className="w-10 h-10 rounded-xl bg-slate-50 text-slate-400 hover:text-primary hover:bg-primary/5 transition-all opacity-0 group-hover:opacity-100"
                                        >
                                            <MoreHorizontal className="w-5 h-5" />
                                        </Button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <div className="px-6 py-4 border-t border-slate-100 bg-slate-50/50 flex items-center justify-between">
                    <p className="text-xs font-medium text-slate-400">
                        Всего записей: <span className="text-slate-900 font-bold">{pagination.total}</span>
                    </p>
                    <div className="flex items-center gap-2">
                        <Button
                            variant="ghost"
                            size="icon"
                            disabled={pagination.page <= 1 || isPending}
                            onClick={() => handlePageChange(pagination.page - 1)}
                            className="w-9 h-9 rounded-xl border border-slate-200 bg-white"
                        >
                            <ChevronLeft className="w-5 h-5" />
                        </Button>
                        <span className="text-xs font-bold px-3">
                            {pagination.page} / {pagination.totalPages}
                        </span>
                        <Button
                            variant="ghost"
                            size="icon"
                            disabled={pagination.page >= pagination.totalPages || isPending}
                            onClick={() => handlePageChange(pagination.page + 1)}
                            className="w-9 h-9 rounded-xl border border-slate-200 bg-white"
                        >
                            <ChevronRight className="w-5 h-5" />
                        </Button>
                    </div>
                </div>
            </div>

            {/* Details Modal */}
            <ResponsiveModal
                isOpen={isDetailsOpen}
                onClose={() => setIsDetailsOpen(false)}
                title="Детали изменения"
                description={`Лог ID: ${selectedLog?.id}`}
                className="max-w-2xl"
            >
                <div className="pb-6">
                    <div className="mb-6 flex items-center justify-between bg-slate-50 p-4 rounded-2xl border border-slate-100">
                        <div className="flex items-center gap-3">
