import { getAuditLogs } from "../actions/security.actions";
import { AuditClient } from "./audit-client";
import { Activity } from "lucide-react";
import { getRoles } from "../actions/roles.actions";
import { getUsers } from "../actions/users.actions";

export const dynamic = "force-dynamic";

export default async function AuditLogsPage({
    searchParams,
}: {
    searchParams: { [key: string]: string | string[] | undefined };
}) {
    const page = Number(searchParams.page) || 1;
    const search = (searchParams.search as string) || "";
    const userId = (searchParams.userId as string) || undefined;
    const entityType = (searchParams.entityType as string) || undefined;
    const startDate = (searchParams.startDate as string) || undefined;
    const endDate = (searchParams.endDate as string) || undefined;

    const [auditResponse, rolesResponse, usersResponse] = await Promise.all([
        getAuditLogs(page, 25, search, userId, entityType, startDate, endDate),
        getRoles(),
        getUsers()
    ]);

    const logs = auditResponse.success ? auditResponse.data.logs : [];
    const pagination = auditResponse.success ? auditResponse.data.pagination : { total: 0, page: 1, limit: 25, totalPages: 1 };
    const roles = rolesResponse.success ? rolesResponse.data : [];
    const users = usersResponse.success ? usersResponse.data : [];

    return (
        <div className="space-y-3 pb-20">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                <div className="flex items-center gap-3 min-w-0">
                    <div className="w-12 h-12 bg-primary/5 rounded-[18px] flex items-center justify-center border border-primary/10 shrink-0">
                        <Activity className="w-6 h-6 text-primary" />
                    </div>
                    <div className="min-w-0">
                        <h1 className="text-2xl font-extrabold text-slate-900 truncate">Логи аудита</h1>
                        <p className="text-slate-500 text-xs font-medium mt-0.5">История всех изменений и действий в системе</p>
                    </div>
                </div>
            </div>

            <AuditClient 
                initialLogs={logs as any} 
                pagination={pagination}
                users={users as any}
            />
        </div>
    );
}

"use client";

import React, { useEffect, useState } from "react";
import { getHeatmapData } from "../actions";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Loader2, AlertTriangle, CheckCircle, Clock } from "lucide-react";
import { cn } from "@/lib/utils";

interface StageStat {
  stageName: string;
  appTypeId: string | null;
  avgDurationMinutes: number;
  totalTasks: number;
  estimatedTime: number;
  efficiency: number;
}

export function HeatmapView() {
  const [data, setData] = useState<StageStat[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const result = await getHeatmapData({ days: 14 });
        if (result.success && result.data) {
          setData(result.data);
        } else {
          setError("Failed to load data");
        }
      } catch (err) {
        setError("An unexpected error occurred");
      } finally {
        setLoading(false);
      }
    }
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center p-12 space-$1-3">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
        <p className="text-sm text-slate-500 animate-pulse font-medium">Анализируем производственные логи...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-8 text-center text-rose-500 bg-rose-50 rounded-2xl border border-rose-100 font-medium">
        {error}
      </div>
    );
  }

  return (
    <div className="space-$1-3">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
        {data.map((stage) => {
          const isBottleneck = stage.efficiency > 1.2; // 20% slower than estimated
          const isEfficient = stage.efficiency < 0.9; // 10% faster than estimated

          return (
            <Card key={stage.stageName} className={cn(
              "overflow-hidden border transition-all hover:shadow-md",
              isBottleneck ? "border-rose-200 bg-rose-50/10" : 
              isEfficient ? "border-emerald-200 bg-emerald-50/10" : "border-slate-200"
            )}>
              <CardHeader className="pb-3">
                <div className="flex justify-between items-start">
                  <CardTitle className="text-base font-bold truncate pr-6">{stage.stageName}</CardTitle>
                  {isBottleneck ? (
                    <AlertTriangle className="w-5 h-5 text-rose-500 shrink-0" />
                  ) : isEfficient ? (
                    <CheckCircle className="w-5 h-5 text-emerald-500 shrink-0" />
                  ) : (
                    <Clock className="w-5 h-5 text-slate-400 shrink-0" />
                  )}
                </div>
                <CardDescription className="text-xs">
                  {stage.totalTasks} задач выполнено
                </CardDescription>
              </CardHeader>
              <CardContent className="space-$1-3">
                <div className="space-y-2">
                  <div className="flex justify-between text-xs font-medium">
                    <span className="text-slate-500">Эффективность</span>
                    <span className={cn(
                        "font-bold",
                        isBottleneck ? "text-rose-600" : isEfficient ? "text-emerald-600" : "text-slate-700"
                    )}>
                        {Math.round(stage.efficiency * 100)}%
                    </span>
                  </div>
                  <Progress 
                    value={Math.min(stage.efficiency * 50, 100)} 
                    className={cn(
                        "h-2",
                        isBottleneck ? "bg-rose-100" : "bg-slate-100"
                    )}
                  />
                  <p className="text-[10px] text-slate-400 leading-tight italic">
                    * Отношение фактического времени к плановому
                  </p>
                </div>

                <div className="flex items-center justify-between pt-2 border-t border-slate-100">
                  <div className="text-center">
                    <p className="text-[10px] text-slate-400 font-bold tracking-wider">Факт</p>
                    <p className="text-sm font-bold text-slate-700">{stage.avgDurationMinutes}м</p>
                  </div>
                  <div className="text-center">
                    <p className="text-[10px] text-slate-400 font-bold tracking-wider">План</p>
                    <p className="text-sm font-bold text-slate-500">{stage.estimatedTime}м</p>
                  </div>
                  <div className="text-right">
                    <Badge variant={isBottleneck ? "destructive" : isEfficient ? "success" : "secondary"} className="h-5 text-[10px] px-1.5 rounded-md font-bold">
                      {isBottleneck ? "УЗКОЕ МЕСТО" : isEfficient ? "ОПТИМАЛЬНО" : "НОРМА"}
                    </Badge>
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {data.length === 0 && (
        <div className="p-12 text-center text-slate-400 font-medium bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
          Данные за выбранный период отсутствуют. 
          <br/>
          Пожалуйста, проверьте наличие завершенных производственных задач.
        </div>
      )}
    </div>
  );
}

