                                            </Button>
                                            <Button className="rounded-xl bg-slate-900 hover:bg-primary transition-all gap-3 text-xs font-bold h-12 w-full shadow-lg shadow-slate-200 text-white group/btn">
                                                Применить
                                                <ArrowRight className="w-4 h-4 group-hover/btn:translate-x-1.5 transition-transform" />
                                            </Button>
                                        </div>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    </Card>
                </div>
            </Tabs>

            {/* Quality Standards & Info */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3 pt-4">
                {[
                    { icon: Eraser, label: "Removal", text: "Прозрачность для печати." },
                    { icon: Maximize, label: "Upscale", text: "Рост качества до 300 DPI." },
                    { icon: FileCode, label: "Vector", text: "Трассировка лого в кривые." },
                    { icon: Type, label: "Typography", text: "AI генерация надписей." }
                ].map((item, i) => (
                    <motion.div 
                        key={i}
                        whileHover={{ y: -6 }}
