"use server";

import { db } from "@/lib/db";
import { customerFeedback } from "@/lib/schema";
import { eq, and } from "drizzle-orm";
import { revalidatePath } from "next/cache";

export async function getFeedbackByToken(token: string) {
    try {
        const feedback = await db.query.customerFeedback.findFirst({
            where: eq(customerFeedback.token, token),
            with: {
                client: true,
                order: true
            }
        });

        if (!feedback) return { success: false, error: "Отзыв не найден" };
        if (feedback.score > 0) return { success: false, error: "Вы уже оставили отзыв. Спасибо!", alreadySubmitted: true };

        return { success: true, data: feedback };
    } catch (error) {
        console.error("Error fetching feedback:", error);
        return { success: false, error: "Произошла ошибка при загрузке" };
    }
}

export async function submitFeedback(token: string, score: number, comment?: string) {
    // audit-ignore (public action secured by single-use token)
    try {
        const [feedback] = await db.select().from(customerFeedback).where(eq(customerFeedback.token, token)).limit(1);

        if (!feedback) return { success: false, error: "Отзыв не найден" };
        if (feedback.score > 0) return { success: false, error: "Отзыв уже был отправлен" };

        await db.update(customerFeedback)
            .set({ 
                score, 
                comment, 
                updatedAt: new Date() 
            })
            .where(eq(customerFeedback.token, token));

        revalidatePath("/dashboard/clients"); // Чтобы обновить статистику если нужно

        return { success: true };
    } catch (error) {
        console.error("Error submitting feedback:", error);
        return { success: false, error: "Не удалось отправить отзыв" };
    }
}

"use client";

import React from "react";
import { useSession } from "@/lib/auth-client";
import { Lock } from "lucide-react";
import { cn } from "@/lib/utils";

export type PermissionPath = 
  | "modules.orders" 
  | "modules.clients" 
  | "modules.warehouse" 
  | "modules.production" 
  | "modules.finance" 
  | "modules.employees" 
  | "modules.admin"
  | "privacy.view_contacts"
  | "privacy.view_costs"
  | "privacy.view_analytics";

interface PermissionShieldProps {
  permission: PermissionPath;
  children: React.ReactNode;
  fallback?: React.ReactNode;
  showIcon?: boolean;
}

/**
 * Компонент-обёртка для разграничения доступа в интерфейсе.
 * Проверяет наличие прав у текущего пользователя.
 */
export function PermissionShield({ 
  permission, 
  children, 
  fallback,
  showIcon = false 
}: PermissionShieldProps) {
  const session = useSession();

  if (session.isPending) return null;

  const user = session.data?.user as any;
  let permissions = user?.permissions || {};

  // Если permissions пришли как строка (JSON), парсим их
  if (typeof permissions === 'string') {
    try {
      permissions = JSON.parse(permissions);
    } catch {
      permissions = {};
    }
  }

  const [category, action] = permission.split(".");
  const hasPermission = permissions[category]?.[action] === true;

  if (hasPermission) {
    return <>{children}</>;
  }

  if (fallback) return <>{fallback}</>;

  if (showIcon) {
    return (
      <div className="flex items-center gap-1.5 text-slate-400 italic text-xs">
        <Lock className="w-3 h-3" />
        <span>Доступ ограничен</span>
      </div>
    );
  }

  return null;
}

/**
 * Хук для проверки прав в логике компонентов
 */
export function usePermission(path: PermissionPath): boolean {
  const session = useSession();
  if (!session.data?.user) return false;

  const user = session.data.user as any;
  let permissions = user?.permissions || {};

  if (typeof permissions === 'string') {
    try {
      permissions = JSON.parse(permissions);
    } catch {
      permissions = {};
    }
  }

  const [category, action] = path.split(".");
  return permissions[category]?.[action] === true;
}

/**
 * Специализированный компонент для скрытия конфиденциальных данных (цены, контакты)
 */
export function PrivacyShield({ 
  type, 
  value, 
  className 
}: { 
  type: "contacts" | "costs" | "analytics", 
  value: React.ReactNode,
  className?: string
}) {
  const permissionMap: Record<string, PermissionPath> = {
    contacts: "privacy.view_contacts",
    costs: "privacy.view_costs",
    analytics: "privacy.view_analytics"
  };

  const hasAccess = usePermission(permissionMap[type]);

  if (hasAccess) {
    return <span className={className}>{value}</span>;
  }

  // Для контактов скрываем часть, для цен — блюрим или заменяем на звездочки
  return (
    <span className={cn("inline-flex items-center gap-1 text-slate-300 font-mono blur-[3.5px] select-none cursor-not-allowed", className)}>
      {typeof value === 'string' ? value.replace(/./g, '*') : '********'}
    </span>
  );
}

