// Отдельный компонент для логотипа, чтобы избежать условных хуков
function DecalLogo({ 
    textureUrl, 
    mesh,
    position = [0, 0, 0],
    rotation = [0, 0, 0],
    scale = [0.3, 0.3, 0.3]
}: { 
    textureUrl: string; 
    mesh: THREE.Mesh;
    position?: [number, number, number];
    rotation?: [number, number, number];
    scale?: [number, number, number];
}) {
    // Используем useTexture с обработкой ошибок через Suspense
    const texture = useTexture(textureUrl);

    // Настройка текстуры для декалей
    useEffect(() => {
