for (const file of filesToFix) {
  const fullPath = path.join(__dirname, file);
  if (fs.existsSync(fullPath)) {
    let content = fs.readFileSync(fullPath, 'utf8');

    // Replace ' as any' with ' as unknown'
    content = content.replace(/ as any/g, ' as unknown');

    // Replace ': any' with ': unknown'
    content = content.replace(/: any\b/g, ': unknown');

    // Replace '<any>' with '<unknown>'
    content = content.replace(/<any>/g, '<unknown>');

    // Replace 'any[]' with 'unknown[]'
    content = content.replace(/any\[\]/g, 'unknown[]');

    // 'any' in destructured params like `(props: any)`
    content = content.replace(/\(props: any\)/g, '(props: unknown)');

    fs.writeFileSync(fullPath, content);
    console.log(`Replaced in ${file}`);
  } else {
    console.log(`Not found: ${file}`);
  }
}

import Redis from "ioredis";
import { env } from "@/lib/env";

const redisOptions = {
  host: env.REDIS_HOST,
  port: env.REDIS_PORT,
  password: env.REDIS_PASSWORD || undefined,
  connectTimeout: 2000,
  retryStrategy: (times: number) => {
    const delay = Math.min(times * 100, 3000);
    return delay;
  },
  maxRetriesPerRequest: 1,
};

// Mock Redis for test environments without a real Redis server
class RedisMock {
  private data: Map<string, string> = new Map();

  async get(key: string) { return this.data.get(key) || null; }
  async set(key: string, value: string, _mode?: string, _duration?: number) { 
    this.data.set(key, value); 
    return "OK"; 
  }
  async del(key: string) { return this.data.delete(key) ? 1 : 0; }
  async incr(key: string) {
    const val = parseInt(this.data.get(key) || "0") + 1;
    this.data.set(key, val.toString());
    return val;
  }
  async expire(_key: string, _seconds: number) { return 1; }
  async ttl(_key: string) { return 60; }

  multi() {
    const commands: (() => Promise<unknown>)[] = [];
    const proxy = {
      incr: (key: string) => {
        commands.push(() => this.incr(key));
        return proxy;
      },
      expire: (key: string, seconds: number) => {
        commands.push(() => this.expire(key, seconds));
        return proxy;
      },
      ttl: (key: string) => {
        commands.push(() => this.ttl(key));
        return proxy;
      },
      exec: async () => {
        const results = [];
        for (const cmd of commands) {
          results.push([null, await cmd()]);
        }
        return results;
      }
    };
    return proxy;
  }

  async keys(pattern: string) {
    const regex = new RegExp("^" + pattern.replace(/\*/g, ".*") + "$");
    return Array.from(this.data.keys()).filter(key => regex.test(key));
  }

  async ping() { return "PONG"; }

  async flushall() { this.data.clear(); return "OK"; }
}

const isTest = process.env.NODE_ENV === "test" || process.env.VITEST === "true";
const skipRedis = process.env.SKIP_REDIS === "true";

/** Singleton Redis instance */
declare global {
  // eslint-disable-next-line no-var
  var redis: Redis | RedisMock | undefined;
}

export const redis = global.redis || (isTest || skipRedis ? new RedisMock() : new Redis(redisOptions));

if (process.env.NODE_ENV !== "production") {
  global.redis = redis;
}

/** Invalidate cache pattern helper */
export async function invalidateCache(pattern: string): Promise<void> {
  try {
    const keys = await redis.keys(pattern);
    if (keys.length > 0) {
      // Use cast to void because we don't care about the return value of del
      await (redis as unknown as { del: (keys: string[]) => Promise<number> }).del(keys);
    }
  } catch (err) {
    console.error(`Redis invalidation error for pattern ${pattern}:`, err);
  }
}

import { db } from "@/lib/db";
import { clients } from "@/lib/schema/clients/main";
import { tasks } from "@/lib/schema/tasks";
import { taskAssignees } from "@/lib/schema/task-assignees";
import { lt, and, isNotNull } from "drizzle-orm";
import { subDays, addDays } from "date-fns";

export class ReactivationService {
    /**
     * Finds clients who haven't ordered in more than 90 days
     * and creates a follow-up task for their manager.
     */
    static async processInactiveClients() {
        const ninetyDaysAgo = subDays(new Date(), 90);

        console.log("[ReactivationService] Starting reactivation check...");

        // 1. Find inactive clients:
        // - lastOrderAt > 90 days ago
        // - status is 'active'
        // - has a managerId
        const inactiveClients = await db.select()
            .from(clients as any)
            .where(
                and(
                    isNotNull(clients.lastOrderAt),
                    lt(clients.lastOrderAt, ninetyDaysAgo),
                    isNotNull(clients.managerId)
                )
            );

        console.log(`[ReactivationService] Found ${inactiveClients.length} inactive clients potentially needing reactivation.`);
        const results: { clientId: string; taskId: string }[] = [];

        for (const client of inactiveClients) {
            if (!client.managerId) continue;

            // Check if there's already an active reactivation task for this client to avoid duplicates
            // We'll skip this for now to keep it simple, but in prod we'd check tasks table for autoCreatedSourceId

            try {
                await db.transaction(async (tx) => {
                    // 2. Create the task
                    const [newTask] = await tx.insert(tasks).values({
                        title: `Реактивация клиента: ${client.name}`,
                        description: `Клиент не делал заказов более 90 дней (последний раз: ${client.lastOrderAt?.toLocaleDateString()}). Необходимо связаться и предложить актуальные новинки или узнать причины затишья.`,
                        status: "new",
                        priority: "high",
                        type: "general",
                        creatorId: client.managerId!, 
                        deadline: addDays(new Date(), 3), // +3 days to complete
                        isAutoCreated: true,
                        autoCreatedReason: "client_inactivity_90d",
                        autoCreatedSourceType: "client",
                        autoCreatedSourceId: client.id,
                    }).returning();

                    // 3. Assign the task to the manager
                    await tx.insert(taskAssignees).values({
                        taskId: newTask.id,
                        userId: client.managerId!,
                        assignedBy: client.managerId!, // System automation context
                    });

                    results.push({ clientId: client.id, taskId: newTask.id });
                });
            } catch (error) {
                console.error(`[ReactivationService] Failed to create reactivation task for client ${client.id}:`, error);
            }
        }

        console.log(`[ReactivationService] Successfully created ${results.length} reactivation tasks.`);
        return results;
    }
}

import { db } from "@/lib/db";
import { orders, orderItems } from "@/lib/schema/orders";
import { applicationTypes } from "@/lib/schema/production";
import { inventoryItems } from "@/lib/schema/warehouse/items";
import { eq, sum } from "drizzle-orm";
import { logError } from "@/lib/error-logger";
import { decimal } from "drizzle-orm/pg-core";

/**
 * Service for financial operations, including cost calculations.
 */
export class FinanceService {
  /**
   * Calculates the full estimated cost for a given order.
   * Updates all items and the main order record.
   * 
   * @param orderId - The unique identifier of the order.
   * @audit FINANCE_CALCULATION
   */
  static async calculateOrderCost(orderId: string): Promise<number> {
    try {
      // 1. Fetch order items with their blanks and application types
      const items = await db.query.orderItems.findMany({
        where: eq(orderItems.orderId, orderId),
        with: {
          inventory: true,
          applicationType: true,
        },
      });

      let totalOrderCost = 0;

      // 2. Calculate cost for each item
      for (const item of items) {
        let itemCost = 0;

        // Blank cost (from inventory items)
        const blankCost = Number(item.inventory?.costPrice || 0);
        itemCost += blankCost * item.quantity;

        // Application cost (from application types)
        if (item.applicationType) {
          const app = item.applicationType;
          // Note: app costs are in kopeks (integer in DB)
          const setupCost = (app.setupCost || 0) / 100;
          const unitCost = (app.baseCost || 0) / 100 + (app.costPerUnit || 0) / 100;
          const amortization = (app.amortizationCost || 0) / 100;

          const applicationCost = setupCost + (unitCost + amortization) * item.quantity;
          itemCost += applicationCost;
        }

        // 3. Update individual item's estimated cost
        await db.update(orderItems)
          .set({ estimatedCost: itemCost.toFixed(2) })
          .where(eq(orderItems.id, item.id));

        totalOrderCost += itemCost;
      }

      // 4. Update order with total cost
      await db.update(orders)
        .set({ totalCost: totalOrderCost.toFixed(2) })
        .where(eq(orders.id, orderId));

      return totalOrderCost;
    } catch (error) {
      await logError({
        error,
        path: "FinanceService.calculateOrderCost",
        method: "POST",
        details: { orderId }
      });
      throw error;
    }
  }

  /**
   * Recalculates all costs for a specific order and returns the margin.
   */
  static async getOrderMargin(orderId: string) {
    const order = await db.query.orders.findFirst({
      where: eq(orders.id, orderId),
      columns: {
        totalAmount: true,
        totalCost: true,
      }
    });

    if (!order) return null;

    const totalAmount = Number(order.totalAmount);
    const totalCost = Number(order.totalCost);
    const margin = totalAmount - totalCost;
    const marginPercentage = totalAmount > 0 ? (margin / totalAmount) * 100 : 0;

    return {
      totalAmount,
      totalCost,
      margin,
      marginPercentage,
    };
  }
}

