    /**
     * Планирует или отправляет запрос NPS для заказа.
     * Обычно вызывается через 3 дня после доставки.
     */
    static async createNPSRequest(orderId: string) {
        try {
            // 1. Получаем данные заказа и клиента
            const order = await db.query.orders.findFirst({
                where: eq(orders.id, orderId),
                with: {
                    client: true
                }
            });

            if (!order || !order.clientId) {
                console.error(`Order ${orderId} not found or has no client.`);
                return null;
            }

            // 2. Проверяем, не отправляли ли уже отзыв по этому заказу
            const existing = await db.query.customerFeedback.findFirst({
                where: eq(customerFeedback.orderId, orderId)
            });

            if (existing) {
                return existing;
            }

            // 3. Создаем запись фидбека (ожидающую заполнения)
            const [feedback] = await db.insert(customerFeedback).values({
                clientId: order.clientId,
                orderId: order.id,
                score: 0, // 0 означает, что еще не заполнено
                token: crypto.randomUUID(),
            }).returning();

            // 4. Логика отправки (Email/Telegram/SMS)
            // В реальном приложении здесь вызывается транспорт (SendGrid, Unisender и т.д.)
            console.log(`NPS Request created for order ${order.orderNumber}. Token: ${feedback.token}`);

            // TODO: Интеграция с сервисом рассылок
            // await NotificationService.sendNPS(order.client.email, feedback.token);

            return feedback;
        } catch (error) {
            console.error("Error creating NPS request:", error);
            return null;
        }
    }

    /**
     * Ищет заказы, доставленные > 3 дней назад, для которых еще нет NPS запроса.
     * Может запускаться по крону.
     */
    static async processPendingNPS() {
        const threeDaysAgo = new Date();
        threeDaysAgo.setDate(threeDaysAgo.getDate() - 3);

        try {
            // Находим заказы: статус доставки 'delivered', дата доставки < 3 дней назад, нет записи в feedback
            const pendingOrders = await db.select({ id: orders.id })
                .from(orders)
                .leftJoin(customerFeedback, eq(orders.id, customerFeedback.orderId))
                .where(and(
                    eq(orders.deliveryStatus, 'delivered'),
                    lt(orders.actualDeliveryDate, threeDaysAgo),
                    isNull(customerFeedback.id)
                ));

            console.log(`Found ${pendingOrders.length} pending NPS requests.`);

            for (const order of pendingOrders) {
                await this.createNPSRequest(order.id);
            }
        } catch (error) {
            console.error("Error processing pending NPS:", error);
        }
    }
}

import { db } from "@/lib/db";
import { productionTasks, productionLogs, applicationTypes } from "@/lib/schema/production";
import { eq, and, gte, lte, sql } from "drizzle-orm";
import { logError } from "@/lib/error-logger";

export interface StageStat {
  stageName: string;
  appTypeId: string | null;
  avgDurationMinutes: number;
  totalTasks: number;
  estimatedTime: number;
  efficiency: number; // actual / estimated
}

export class HeatmapService {
  /**
   * Analyzes production logs to find bottlenecks in the production hall.
   * Calculates the average actual time spent on tasks vs estimated time.
   */
  static async getProductionBottlenecks(days: number = 7): Promise<StageStat[]> {
    try {
      const startDate = new Date();
      startDate.setDate(startDate.getDate() - days);

      // 1. Fetch completed tasks with their logs
      const tasks = await db.query.productionTasks.findMany({
        where: and(
          eq(productionTasks.status, "completed"),
          gte(productionTasks.completedAt, startDate)
        ),
        with: {
          logs: {
            where: sql`${productionLogs.event} IN ('started', 'completed')`,
            orderBy: [productionLogs.createdAt],
          },
          applicationType: true,
        },
      });

      const statsMap: Record<string, { totalDuration: number, count: number, estimated: number, name: string }> = {};

      for (const task of tasks) {
        const startedLog = task.logs.find(l => l.event === "started");
        const completedLog = task.logs.find(l => l.event === "completed");

        if (startedLog && completedLog) {
          const durationMs = completedLog.createdAt.getTime() - startedLog.createdAt.getTime();
          const durationMins = durationMs / (1000 * 60);

          const appId = task.applicationTypeId || "manual";
          const appName = task.applicationType?.name || task.title;

          if (!statsMap[appId]) {
            statsMap[appId] = { totalDuration: 0, count: 0, estimated: 0, name: appName };
          }

          statsMap[appId].totalDuration += durationMins;
          statsMap[appId].count += 1;
          statsMap[appId].estimated += (task.estimatedTime || 0);
        }
      }

      // 2. Format results
      const results: StageStat[] = Object.entries(statsMap).map(([id, data]) => {
        const avgDuration = data.totalDuration / data.count;
        const avgEstimated = data.estimated / data.count;
        const efficiency = avgEstimated > 0 ? (avgDuration / avgEstimated) : 1;

        return {
          stageName: data.name,
          appTypeId: id === "manual" ? null : id,
          avgDurationMinutes: Math.round(avgDuration),
          totalTasks: data.count,
          estimatedTime: Math.round(avgEstimated),
          efficiency: Number(efficiency.toFixed(2)),
        };
      });

      // Sort by efficiency descending (highest efficiency = worst bottleneck)
      return results.sort((a, b) => b.efficiency - a.efficiency);
    } catch (error) {
      await logError({
        error,
        path: "HeatmapService.getProductionBottlenecks",
        method: "GET"
      });
      return [];
    }
  }

  /**
   * Returns a simplified list of app types that are currently running slow.
   */
  static async getSlowStages() {
    const stats = await this.getProductionBottlenecks(30);
    return stats.filter(s => s.efficiency > 1.25); // 25% slower than estimated
  }
}

const fs = require('fs');
const path = require('path');

const untrackedFiles = [
  "app/(main)/admin-panel/api-keys/page.tsx",
  "app/(main)/admin-panel/audit/audit-client.tsx",
  "app/(main)/admin-panel/audit/page.tsx",
  "app/(main)/admin-panel/roles-departments/page.tsx",
  "app/(main)/dashboard/portal/portal-client.tsx",
  "app/api/cron/clients/reactivation/route.ts",
  "app/api/cron/nps/route.ts",
  "app/api/v1/orders/route.ts",
  "components/auth/permission-shield.tsx",
  "components/portal/ticket-modal.tsx",
];

for (const file of untrackedFiles) {
  const fullPath = path.join(__dirname, file);
  if (fs.existsSync(fullPath)) {
    let content = fs.readFileSync(fullPath, 'utf8');

    // Reverse replacements
    content = content.replace(/ as unknown/g, ' as any');
    content = content.replace(/: unknown\b/g, ': any');
    content = content.replace(/<unknown>/g, '<any>');
    content = content.replace(/unknown\[\]/g, 'any[]');
    content = content.replace(/\(props: unknown\)/g, '(props: any)');

    fs.writeFileSync(fullPath, content);
    console.log(`Reverted in ${file}`);
  }
}
